SELECT COUNT(*) AS completed_task_count
FROM task_metrics
WHERE processing_status = 'completed';

SELECT task_type, COUNT(*) AS task_count
FROM tasks
GROUP BY task_type;

SELECT count_ms, lookup_mus
FROM performance_metrics
ORDER BY count_ms DESC;

SELECT DISTINCT u.user_name
FROM users u
JOIN reporting r ON u.user_id = r.user_id;

SELECT AVG(count_ms) AS average_processing_time
FROM performance_metrics
WHERE error_count > 0;

SELECT task_name, task_priority
FROM tasks
ORDER BY task_priority DESC;
